import React, { useState, useRef, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import {
  createProduct, getProductByBarcode, searchProducts,
  createPurchaseBill, getVendors, createVendor
} from '../services/api';

const UNITS = ['nos', 'kg', 'carton'];
const fmt   = n => `₹${parseFloat(n || 0).toFixed(2)}`;

// ─────────────────────────────────────────────────────────────────────────────
// Create Product Modal
// ─────────────────────────────────────────────────────────────────────────────
function CreateProductModal({ onClose, onCreated }) {
  const [form,    setForm]    = useState({ barcode: '', name: '', auto_barcode: false });
  const [loading, setLoading] = useState(false);
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.name) { toast.error('Product name required'); return; }
    setLoading(true);
    try {
      const payload = { name: form.name, selling_price: 0 };
      if (!form.auto_barcode && form.barcode) payload.barcode = form.barcode;
      const { data } = await createProduct(payload);
      toast.success(`"${data.name}" created! Barcode: ${data.barcode}`);
      onCreated(data);
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.barcode?.[0] || 'Failed to create product');
    } finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>📦 Create New Product</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Product Name *</label>
            <input autoFocus value={form.name} onChange={e => set('name', e.target.value)}
              placeholder="e.g. Chocolate Cake" />
          </div>
          <div className="form-group">
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, textTransform: 'none', letterSpacing: 0 }}>
              <input type="checkbox" checked={form.auto_barcode}
                onChange={e => set('auto_barcode', e.target.checked)} style={{ width: 'auto' }} />
              Auto-generate Barcode
            </label>
          </div>
          {!form.auto_barcode && (
            <div className="form-group">
              <label>Barcode (leave blank to auto-generate)</label>
              <input value={form.barcode} onChange={e => set('barcode', e.target.value)}
                placeholder="Scan or enter barcode" style={{ fontFamily: 'var(--mono)' }} />
            </div>
          )}
          <div style={{ display: 'flex', gap: 10 }}>
            <button type="submit" className="btn btn-primary"
              style={{ flex: 1, justifyContent: 'center' }} disabled={loading}>
              {loading ? 'Creating…' : '✓ Create Product'}
            </button>
            <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Create Vendor Modal
// ─────────────────────────────────────────────────────────────────────────────
function CreateVendorModal({ onClose, onCreated }) {
  const [name,    setName]    = useState('');
  const [phone,   setPhone]   = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async e => {
    e.preventDefault();
    if (!name.trim()) { toast.error('Vendor name required'); return; }
    setLoading(true);
    try {
      const { data } = await createVendor({ name, phone: phone || null });
      toast.success(`Vendor "${data.name}" created`);
      onCreated(data);
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.name?.[0] || 'Failed to create vendor');
    } finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay">
      <div className="modal" style={{ maxWidth: 400 }}>
        <h2>🏪 Create Vendor</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Vendor Name *</label>
            <input autoFocus value={name} onChange={e => setName(e.target.value)}
              placeholder="e.g. Fresh Foods Pvt Ltd" />
          </div>
          <div className="form-group">
            <label>Phone (optional)</label>
            <input value={phone} onChange={e => setPhone(e.target.value)}
              placeholder="e.g. 9876543210" type="tel" />
          </div>
          <div style={{ display: 'flex', gap: 10 }}>
            <button type="submit" className="btn btn-primary"
              style={{ flex: 1, justifyContent: 'center' }} disabled={loading}>
              {loading ? 'Creating…' : '✓ Create Vendor'}
            </button>
            <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Product Search Cell
// ─────────────────────────────────────────────────────────────────────────────
function ProductSearchCell({ value, onSelect }) {
  const [query,     setQuery]     = useState(value?.name || '');
  const [results,   setResults]   = useState([]);
  const [searching, setSearching] = useState(false);
  const debounceRef  = useRef();
  const resultsRef   = useRef([]);
  resultsRef.current = results;

  const doSearch = useCallback(async q => {
    if (!q.trim()) { setResults([]); return; }
    setSearching(true);
    try {
      const { data } = await searchProducts(q);
      setResults(data);
    } catch { setResults([]); }
    finally { setSearching(false); }
  }, []);

  const handleChange = e => {
    const v = e.target.value;
    setQuery(v);
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => doSearch(v), 300);
  };

  const pick = p => {
    setQuery(p.name);
    setResults([]);
    onSelect(p);
  };

  const handleKeyDown = async e => {
    if (e.key === 'Enter') {
      e.preventDefault();
      clearTimeout(debounceRef.current);
      if (resultsRef.current.length > 0) { pick(resultsRef.current[0]); return; }
      const q = query.trim(); if (!q) return;
      try { const { data } = await getProductByBarcode(q); pick(data); }
      catch { toast.error('Product not found'); }
    }
    if (e.key === 'Escape') { setResults([]); }
  };

  return (
    <div style={{ position: 'relative', minWidth: 180 }}>
      <input
        value={query}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        placeholder="Scan / search…"
        style={{ fontSize: 13, padding: '6px 10px' }}
      />
      {searching && (
        <div style={{ position: 'absolute', right: 8, top: 8, fontSize: 11, color: 'var(--text3)' }}>…</div>
      )}
      {results.length > 0 && (
        <div style={{
          position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 300,
          background: 'var(--surface)', border: '1px solid var(--border)',
          borderRadius: 'var(--radius)', marginTop: 2,
          boxShadow: 'var(--shadow)', maxHeight: 220, overflowY: 'auto'
        }}>
          {results.map(p => (
            <div key={p.id} onClick={() => pick(p)} style={{
              padding: '8px 12px', cursor: 'pointer',
              borderBottom: '1px solid var(--border)', fontSize: 13,
            }}
              onMouseEnter={e => e.currentTarget.style.background = 'var(--accent-dim)'}
              onMouseLeave={e => e.currentTarget.style.background = ''}>
              <div style={{ fontWeight: 600 }}>{p.name}</div>
              <div style={{ fontSize: 11, color: 'var(--text3)', fontFamily: 'var(--mono)' }}>{p.barcode}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Empty row template
// ─────────────────────────────────────────────────────────────────────────────
const emptyRow = () => ({
  _id:            Date.now() + Math.random(),
  product:        null,
  purchase_unit:  'nos',
  quantity:       '',
  purchase_price: '',
  tax:            '0',
  mrp:            '',
  selling_unit:   'nos',
});

// ─────────────────────────────────────────────────────────────────────────────
// Main Purchase Page
// ─────────────────────────────────────────────────────────────────────────────
export default function Purchase() {
  const [vendors,        setVendors]        = useState([]);
  const [selectedVendor, setSelectedVendor] = useState('');
  const [rows,           setRows]           = useState([emptyRow()]);
  const [loading,        setLoading]        = useState(false);
  const [showProduct,    setShowProduct]    = useState(false);
  const [showVendor,     setShowVendor]     = useState(false);

  useEffect(() => {
    getVendors().then(r => setVendors(r.data));
  }, []);

  const fetchVendors = () => getVendors().then(r => setVendors(r.data));

  const updateRow = (id, field, value) => {
    setRows(prev => prev.map(r => r._id === id ? { ...r, [field]: value } : r));
  };

  const selectProduct = (id, product) => {
    setRows(prev => prev.map(r => r._id === id ? {
      ...r,
      product,
      mrp:          product.selling_price ? String(product.selling_price) : '',
      selling_unit: product.selling_unit  || 'nos',
    } : r));
  };

  const addRow    = () => setRows(prev => [...prev, emptyRow()]);
  const removeRow = id => setRows(prev => prev.length > 1 ? prev.filter(r => r._id !== id) : prev);

  const handleSubmit = async () => {
    // Vendor is mandatory
    if (!selectedVendor) {
      toast.error('Please select a vendor');
      return;
    }
    for (const row of rows) {
      if (!row.product)        { toast.error('Select a product for each row');     return; }
      if (!row.quantity)       { toast.error('Enter quantity for each row');        return; }
      if (!row.purchase_price) { toast.error('Enter purchase price for each row'); return; }
      if (!row.mrp)            { toast.error('Enter MRP for each row');            return; }
    }

    setLoading(true);
    try {
      const payload = {
        vendor: selectedVendor,
        items: rows.map(r => ({
          product:        r.product.id,
          purchase_unit:  r.purchase_unit,
          quantity:       parseFloat(r.quantity),
          purchase_price: parseFloat(r.purchase_price),
          tax:            parseFloat(r.tax) || 0,
          mrp:            parseFloat(r.mrp),
          selling_unit:   r.selling_unit,
        })),
      };
      await createPurchaseBill(payload);
      toast.success(`Purchase recorded! ${rows.length} item${rows.length > 1 ? 's' : ''} added to stock.`);
      setRows([emptyRow()]);
      setSelectedVendor('');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to record purchase');
    } finally { setLoading(false); }
  };

  const totalValue = rows.reduce((s, r) => {
    const qty   = parseFloat(r.quantity)       || 0;
    const price = parseFloat(r.purchase_price) || 0;
    const tax   = parseFloat(r.tax)            || 0;
    return s + (qty * price * (1 + tax / 100));
  }, 0);

  return (
    <div>
      <div className="page-header">
        <h1>📦 Purchase</h1>
        <div style={{ display: 'flex', gap: 10 }}>
          {/* Only Create Vendor button — no inline "New Vendor" */}
          <button className="btn btn-secondary" onClick={() => setShowVendor(true)}>
            🏪 Create Vendor
          </button>
          <button className="btn btn-primary" onClick={() => setShowProduct(true)}>
            + Create Product
          </button>
        </div>
      </div>

      {/* Vendor selector — mandatory */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="form-group" style={{ margin: 0 }}>
          <label>
            Vendor *
            {!selectedVendor && (
              <span style={{ color: 'var(--red)', marginLeft: 8, fontWeight: 400, textTransform: 'none', letterSpacing: 0 }}>
                — required
              </span>
            )}
          </label>
          <select
            value={selectedVendor}
            onChange={e => setSelectedVendor(e.target.value)}
            style={{ borderColor: !selectedVendor ? 'var(--red)' : undefined }}
          >
            <option value="">— Select vendor —</option>
            {vendors.map(v => (
              <option key={v.id} value={v.id}>
                {v.name}{v.phone ? ` · ${v.phone}` : ''}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Purchase items table */}
      <div className="card" style={{ padding: 0, overflow: 'hidden', marginBottom: 16 }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ minWidth: 900 }}>
            <thead>
              <tr>
                <th style={{ minWidth: 200 }}>Product</th>
                <th style={{ minWidth: 90 }}>Purchase Unit</th>
                <th style={{ minWidth: 90 }}>Qty</th>
                <th style={{ minWidth: 120 }}>Purchase Price (₹)</th>
                <th style={{ minWidth: 80 }}>Tax (%)</th>
                <th style={{ minWidth: 120 }}>MRP / Selling Price (₹)</th>
                <th style={{ minWidth: 90 }}>Selling Unit</th>
                <th style={{ minWidth: 44 }}></th>
              </tr>
            </thead>
            <tbody>
              {rows.map(row => (
                <tr key={row._id}>
                  {/* Product search */}
                  <td style={{ padding: '8px 10px' }}>
                    <ProductSearchCell
                      value={row.product}
                      onSelect={p => selectProduct(row._id, p)}
                    />
                    {row.product && (
                      <div style={{ fontSize: 11, color: 'var(--text3)', fontFamily: 'var(--mono)', marginTop: 3 }}>
                        {row.product.barcode}
                      </div>
                    )}
                  </td>

                  {/* Purchase unit */}
                  <td style={{ padding: '8px 6px' }}>
                    <select value={row.purchase_unit}
                      onChange={e => updateRow(row._id, 'purchase_unit', e.target.value)}
                      style={{ fontSize: 13, padding: '6px 8px' }}>
                      {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                    </select>
                  </td>

                  {/* Quantity */}
                  <td style={{ padding: '8px 6px' }}>
                    <input type="number" value={row.quantity}
                      onChange={e => updateRow(row._id, 'quantity', e.target.value)}
                      placeholder="0" min="0" step="0.001"
                      style={{ fontSize: 13, padding: '6px 8px', textAlign: 'right' }} />
                  </td>

                  {/* Purchase price */}
                  <td style={{ padding: '8px 6px' }}>
                    <input type="number" value={row.purchase_price}
                      onChange={e => updateRow(row._id, 'purchase_price', e.target.value)}
                      placeholder="0.00" min="0" step="0.01"
                      style={{ fontSize: 13, padding: '6px 8px', textAlign: 'right' }} />
                  </td>

                  {/* Tax */}
                  <td style={{ padding: '8px 6px' }}>
                    <input type="number" value={row.tax}
                      onChange={e => updateRow(row._id, 'tax', e.target.value)}
                      placeholder="0" min="0" step="0.01"
                      style={{ fontSize: 13, padding: '6px 8px', textAlign: 'right' }} />
                  </td>

                  {/* MRP */}
                  <td style={{ padding: '8px 6px' }}>
                    <input type="number" value={row.mrp}
                      onChange={e => updateRow(row._id, 'mrp', e.target.value)}
                      placeholder="0.00" min="0" step="0.01"
                      style={{ fontSize: 13, padding: '6px 8px', textAlign: 'right' }} />
                  </td>

                  {/* Selling unit */}
                  <td style={{ padding: '8px 6px' }}>
                    <select value={row.selling_unit}
                      onChange={e => updateRow(row._id, 'selling_unit', e.target.value)}
                      style={{ fontSize: 13, padding: '6px 8px' }}>
                      {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                    </select>
                  </td>

                  {/* Remove */}
                  <td style={{ padding: '8px 6px', textAlign: 'center' }}>
                    <button className="btn btn-danger btn-sm"
                      onClick={() => removeRow(row._id)}
                      style={{ padding: '4px 8px' }}
                      disabled={rows.length === 1}>
                      ✕
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Add row + summary */}
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          padding: '12px 16px', borderTop: '1px solid var(--border)', background: 'var(--bg2)'
        }}>
          <button className="btn btn-secondary btn-sm" onClick={addRow}>+ Add Item Row</button>
          <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
            <span style={{ color: 'var(--text3)', fontSize: 13 }}>
              {rows.length} item{rows.length !== 1 ? 's' : ''}
            </span>
            <div>
              <span style={{ color: 'var(--text3)', fontSize: 13, marginRight: 10 }}>
                Total Purchase Value (incl. tax)
              </span>
              <span style={{ fontFamily: 'var(--mono)', fontWeight: 800, fontSize: 20, color: 'var(--accent)' }}>
                {fmt(totalValue)}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Submit */}
      <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
        <button className="btn btn-primary" onClick={handleSubmit} disabled={loading}
          style={{ padding: '12px 32px', fontSize: 15 }}>
          {loading ? 'Saving…' : '✓ Record Purchase'}
        </button>
      </div>

      {showProduct && (
        <CreateProductModal onClose={() => setShowProduct(false)} onCreated={() => {}} />
      )}
      {showVendor && (
        <CreateVendorModal
          onClose={() => setShowVendor(false)}
          onCreated={v => { fetchVendors(); setSelectedVendor(String(v.id)); }}
        />
      )}
    </div>
  );
}
